  ('aboriginal-f0899a01-moex-00032', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '下列何者非屬行政法之法源？', '["領海及鄰接區公約", "金門縣政府組織自治條例", "衛生福利部公告之調整全民健保保險費率", "行政法院判例"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "a620b6990aa3", "answer_pdf_sha1": "42723ac4e3be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00033', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於誠信原則之敘述，下列何者正確？', '["誠信原則僅為民事法之法律原則，並不適用於行政行為", "行政契約之雙方當事人應本於誠信原則履行契約義務", "誠信原則之適用取決於各該行政法規中是否有明文規定", "現行行政程序法並無明定誠信原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "a620b6990aa3", "answer_pdf_sha1": "42723ac4e3be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00034', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '下列何種行政行為，須有法律之依據？', '["舉辦園遊會", "在公園內興建遊樂設施", "禁止甲於海邊垂釣", "發放加菜金於消防隊"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "a620b6990aa3", "answer_pdf_sha1": "42723ac4e3be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00035', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於依法行政原則，下列敘述何者正確？', '["法律優於行政規則是屬於積極依法行政之內涵", "大學在招生簡章中設置招生條件缺乏法律依據，不符合法律保留原則", "法律授權行政機關訂定法規命令時，應符合授權明確性原則", "警察機關受理民眾刑案報案作業要點亦得作為干預人民權利之依據"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "a620b6990aa3", "answer_pdf_sha1": "42723ac4e3be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00036', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '下列何者非屬私經濟行政？', '["退休公務人員與臺灣銀行締結優惠存款契約", "國防部訂購武器", "政府於疫情期間向廠商徵用口罩", "農業部大量進口雞蛋出售，以穩定雞蛋價格"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "a620b6990aa3", "answer_pdf_sha1": "42723ac4e3be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL)
